(function () {
    function triggerForm(form) {
        var url = form.getAttribute('hx-post');
        if (!url) return;
        var body = new URLSearchParams(new FormData(form)).toString();
        fetch(url, {
            method: 'POST',
            headers: {
                'Content-Type': 'application/x-www-form-urlencoded',
                'HX-Request': 'true'
            },
            body: body
        }).then(function () {
            document.body.dispatchEvent(new CustomEvent('htmx:afterRequest'));
        });
    }

    document.addEventListener('change', function (event) {
        var form = event.target.closest('form[hx-post][hx-trigger*="change"]');
        if (!form) return;
        triggerForm(form);
    });
})();
